var sortableDoc = ComponentDoc{
	Attributes: []DocAttribute{
		{Name: "orientation", Type: `"vertical" | "horizontal" | "grid"`, Default: `"vertical"`, Observed: true,
			Description: templ.Raw("Constrains pointer travel and the reorder axis. <code>vertical</code> is a column, <code>horizontal</code> a row, <code>grid</code> a 2-D auto-fill grid.")},
		{Name: "disabled", Type: "boolean", Default: "false", Observed: true,
			Description: templ.Raw("Freezes reordering and removes the keyboard grip (grips become <code>tabindex=-1</code>).")},
		{Name: "unbounded", Type: "boolean", Default: "false",
			Description: templ.Raw("By default the floating dragged element is clamped to the host's bounding box so an item can't be dragged outside the list (the lower bound wins if an item is larger than the host). <code>unbounded</code> opts out, letting it follow the pointer anywhere on the page.")},
		{Name: "easing", Type: "string", Default: "theme easing",
			Description: templ.Raw("Transition for the displaced (non-dragged) items as they glide to their new slot. Absent → the theme easing (<code>--neo-easing</code>) at <code>--neo-sortable-move-duration</code>. Empty string → no animation (instant). A bare duration (<code>220ms</code>) pairs with <code>--neo-easing</code>; a full pair (<code>220ms ease-in-out</code>) is used verbatim.")},
		{Name: "tolerate-reorder", Type: "boolean", Default: "false",
			Description: templ.Raw("Controls how an in-flight drag survives an external morph (e.g. a Datastar fat-morph). By default a drag is kept alive only by a no-op morph: same item ids, same per-id content, same order of the other rows. <code>tolerate-reorder</code> loosens that to the same id set: an order-only morph is treated as a no-op and the gesture continues. Any added, removed, or swapped id still cancels the drag.")},
	},
	Slots: []DocSlot{
		{Name: "default",
			Description: templ.Raw("The sortable items: the host's direct element children. Give each a stable <code>id</code> (or <code>data-neo-sortable-id</code>) so the reorder events can name the moved item. Mark a child <code>data-neo-sortable-ignore</code> to exclude it from the set.")},
		{Name: "[data-neo-sortable-item]",
			Description: templ.Raw("Opts an item into the default styling (a bordered row with the handle leading). The Templ <code>SortableItem</code> wrapper adds it automatically; in raw HTML it is optional, drop it to style items yourself.")},
		{Name: "[data-neo-sortable-handle]",
			Description: templ.Raw("Optional drag grip inside an item. With a handle, only that subtree starts a drag; without one the whole item is the grip.")},
		{Name: "[data-neo-sortable-nodrag]",
			Description: templ.Raw("Marks a region inside a whole-item grip that must not start a drag, so pressing it interacts normally. Native controls (links, buttons, form fields, <code>contenteditable</code>) are already exempt; use this for anything else. Ignored when the item has an explicit <code>data-neo-sortable-handle</code>.")},
		{Name: "template[data-neo-sortable-placeholder]",
			Description: templ.Raw("Optional <code>&lt;template&gt;</code> whose content replaces the default dashed placement indicator (the gap shown where the dragged item will land). The gap keeps the dragged item's size; the slotted markup renders inside it.")},
	},
	Events: []DocEvent{
		{Name: "neo-sortable-start", Detail: "{ id: string, index: number }", Bubbles: true,
			Description: templ.Raw("Fires when a drag (pointer or keyboard pick-up) begins. <code>index</code> is the picked-up item's position.")},
		{Name: "neo-sortable-move", Detail: "{ id: string, from: number, to: number }", Bubbles: true,
			Description: templ.Raw("Fires on every reorder during the gesture: item <code>id</code> moved from index <code>from</code> to index <code>to</code>.")},
		{Name: "neo-sortable-end", Detail: "{ id: string, from: number, to: number, changed: boolean, aborted?: boolean }", Bubbles: true,
			Description: templ.Raw("Fires when the drag ends (drop, cancel, or blur). <code>from</code> / <code>to</code> are the item's start and final positions; <code>changed</code> is false when they match or the gesture was cancelled. An external patch that aborts an in-flight drag sets <code>aborted: true</code> with <code>to: -1</code>.")},
	},
	CSSProps: []DocCSSProp{
		{Name: "--neo-sortable-gap", Default: "0.5rem",
			Description: templ.Raw("Gap between items.")},
		{Name: "--neo-sortable-grid-min", Default: "7rem",
			Description: templ.Raw("Minimum column width in <code>grid</code> orientation.")},
		{Name: "--neo-sortable-move-duration", Default: "180ms",
			Description: templ.Raw("Default glide duration for displaced items when the <code>easing</code> attribute is absent.")},
		{Name: "--neo-sortable-drag-shadow", Default: "var(--neo-card-shadow)",
			Description: templ.Raw("Box shadow on the lifted item.")},
		{Name: "--neo-sortable-drag-ring", Default: "inset 0 0 0 2px var(--accent, #6366f1)",
			Description: templ.Raw("Ring on the lifted item, kept legible on dark backgrounds.")},
		{Name: "--neo-sortable-handle-color", Default: "var(--muted, currentColor)",
			Description: templ.Raw("Handle color at rest.")},
		{Name: "--neo-sortable-handle-hover-color", Default: "var(--page-fg, currentColor)",
			Description: templ.Raw("Handle color on hover or focus.")},
		{Name: "--neo-sortable-placeholder-color", Default: "color-mix(in srgb, var(--accent, #6366f1) 55%, transparent)",
			Description: templ.Raw("Color of the dashed placement indicator.")},
	},
}

